#include <bits/stdc++.h>
using namespace std;
#define ull unsigned long long
const long long N=500005,base=2333;
string s;
ull n,a[N],ans,b[N],t[N];
bool check(int l,int mid)
{
	int r=mid+(mid-l)+1;
	ull num1=a[mid]-a[l-1]*t[mid-l+1],num2=b[mid+1]-b[r+1]*t[mid-l+1];
	if(num1==num2)
	{
		return 1;
	}
	return 0;
}
int main()
{
	cin>>n>>s;
	s=" "+s;
	t[0]=1;
	for(int i=1;i<=n;i++)
	{
		t[i]=t[i-1]*base;
		a[i]=(a[i-1]*base+(s[i]-'0'));
	}
	for(int i=n;i>=1;i--)
	{
		b[i]=(b[i+1]*base+!(s[i]-'0'));
	}
	for(int i=1;i<n;i++)
	{
		int l=max(i-(int)n+i+1,1),r=i,mid;
		while(l<=r)
		{
			mid=(l+r)/2;
			if(check(mid,i))
			{
				r=mid-1;
			}
			else l=mid+1;
		}
		ans+=(i-r);
	}
	cout<<ans;
	return 0;
}
